import{_ as e,c as t,o as i,ae as r}from"./chunks/framework.B7Y1jjX-.js";const _=JSON.parse('{"title":"Dano的知识库","description":"","frontmatter":{},"headers":[],"relativePath":"generated-notes/README.md","filePath":"generated-notes/README.md"}'),l={name:"generated-notes/README.md"};function o(n,a,p,s,d,c){return i(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="dano的知识库" tabindex="-1">Dano的知识库 <a class="header-anchor" href="#dano的知识库" aria-label="Permalink to &quot;Dano的知识库&quot;">​</a></h1><p>这是我的个人知识库仓库，用来统一存放和整理所有的 Obsidian 笔记。</p><p>这里记录的不只是简单的学习摘抄，还包括日常开发中的知识沉淀、项目实践中的问题总结，以及对常见技术主题的系统化整理。相比把内容分散在不同位置，这个仓库更像一个可以持续积累、持续回顾、持续完善的个人知识空间。</p><h2 id="知识库包含什么内容" tabindex="-1">知识库包含什么内容 <a class="header-anchor" href="#知识库包含什么内容" aria-label="Permalink to &quot;知识库包含什么内容&quot;">​</a></h2><p>当前知识库主要围绕技术学习和项目实践展开，内容覆盖多个方向，包括但不限于：</p><ul><li>前端基础与进阶内容，比如 HTML、CSS、JavaScript、TypeScript、浏览器原理、工程化与性能优化。</li><li>常用框架与工具相关笔记，比如 Vue、React、Vite、Webpack、Git、Docker、npm 等。</li><li>后端与数据库相关内容，比如 Java、Express、SQL，以及部分开发环境与工具链整理。</li><li>项目笔记与问题记录，比如页面实现思路、功能开发过程、踩坑总结和业务场景分析。</li></ul><h2 id="这个知识库的作用" tabindex="-1">这个知识库的作用 <a class="header-anchor" href="#这个知识库的作用" aria-label="Permalink to &quot;这个知识库的作用&quot;">​</a></h2><p>维护这个知识库的核心目的，是把零散的学习记录和实践经验整理成可复用、可检索、可迭代的资料。</p><p>很多内容在第一次学习时能够理解，但如果没有及时归档和反复整理，后续在真正使用时仍然容易遗忘。把笔记放在这里，可以帮助我在需要的时候更快找到答案，也能在持续补充的过程中逐步形成更清晰的知识结构。</p><p>这个知识库主要服务于以下场景：</p><ul><li>学习某个知识点时，沉淀阶段性理解和重点结论。</li><li>做项目时，回查之前总结过的实现方案和经验。</li><li>复习时，快速定位某一类主题下的相关笔记。</li><li>长期积累时，把零散知识逐步整理成结构化内容。</li></ul><h2 id="组织方式" tabindex="-1">组织方式 <a class="header-anchor" href="#组织方式" aria-label="Permalink to &quot;组织方式&quot;">​</a></h2><p>仓库中的内容按照主题和技术方向进行分类，例如前端、后端、公共技术、学习记录等。这样的组织方式方便按领域查找，也便于后续继续补充新的专题。</p><p>随着学习内容和项目经验不断增加，这个知识库也会持续更新、修订和重构，让已有内容更清晰，也更方便以后再次使用。</p>',14)])])}const u=e(l,[["render",o]]);export{_ as __pageData,u as default};
